 90   CmpInst::Predicate ExpectedPred, Pred1, Pred2;
 91   if (BinOpCode == BinaryOperator::Or) {
 92     ExpectedPred = ICmpInst::ICMP_NE;
 93   } else if (BinOpCode == BinaryOperator::And) {
 94     ExpectedPred = ICmpInst::ICMP_EQ;
 95   } else
 96     return nullptr;
 97 
